1	// AST-Bench V3 — canonical derivation oracle + de-leaked raw-fact scenarios.
2	//
3	// This module is the SINGLE SOURCE OF TRUTH for what a correct answer is. The
4	// fixtures contain ONLY raw business facts (no expected_outcome, no owner list,
5	// no risk-signal list, no customer message). The agent must DERIVE the answer
6	// from raw facts using the business rules documented in the workspace; the
7	// acceptance test re-derives the expected answer here and checks the agent's
8	// PERSISTED live-DB state against it. Copying a status string cannot pass,
9	// because negative-control accounts have a different correct answer.
10	//
11	// The rules below are mirrored verbatim, in prose, in the workspace RULES.md so
12	// the agent and this oracle agree. Rules are lane-independent; only the data
13	// SHAPE differs between mongo / postgres-norm / postgres-jsonb.
14	
15	export const NOW = "2026-06-18T12:00:00.000Z";
16	
17	export const RULES = {
18	  invoiceHighCents: 2_500_000, // $25,000
19	  usageDropFraction: 0.30, // >=30% period-over-period decline
20	  qualifyingTiers: ["strategic", "enterprise"],
21	  highSupportSeverities: ["high", "critical"],
22	  escalationStatus:
23	    "At-risk escalation active with executive recovery owner routing and customer-visible audit history.",
24	  monitorStatus: "Monitoring — no escalation required."
25	};
26	
27	// Fixed category → owner-group mapping and priority order. Owners are derived
28	// purely from which risk categories fired; order is deterministic.
29	const OWNER_FOR_CATEGORY = {
30	  regulatory: "Legal",
31	  invoice: "Finance",
32	  shipment: "Customer Success",
33	  usage: "Customer Success",
34	  support: "Support"
35	};
36	const OWNER_ORDER = ["Legal", "Finance", "Customer Success", "Support"];
37	
38	// Signal display order + names, keyed by category.
39	const SIGNAL_ORDER = ["regulatory", "invoice", "shipment", "support", "usage"];
40	const SIGNAL_NAME = {
41	  regulatory: "Regulatory hold",
42	  invoice: "Overdue invoice",
43	  shipment: "Delayed shipment",
44	  support: "Escalated support",
45	  usage: "Usage decline"
46	};
47	
48	function ms(date) {
49	  return Date.parse(date);
50	}
51	
52	// Evaluate raw facts → which risk categories fired (with human detail).
53	// `world` is the lane-independent fact bundle (see scenarios below).
54	export function evaluateRisks(world, now = NOW) {
55	  const nowMs = ms(now);
56	  const fired = {};
57	
58	  const overdueInvoice = (world.invoices || []).find(
59	    (inv) => inv.status !== "paid" && ms(inv.dueDate) < nowMs && inv.amountCents >= RULES.invoiceHighCents
60	  );
61	  if (overdueInvoice) {
62	    fired.invoice = `Invoice ${overdueInvoice.invoiceId} for $${Math.round(overdueInvoice.amountCents / 100).toLocaleString("en-US")} past due.`;
63	  }
64	
65	  const lateShipment = (world.shipments || []).find(
66	    (sh) => !sh.deliveredDate && ms(sh.slaDate) < nowMs
67	  );
68	  if (lateShipment) {
69	    fired.shipment = `Shipment ${lateShipment.shipmentId} past its delivery commitment.`;
70	  }
71	
72	  const openReg = (world.regulatoryFlags || []).find((flag) => flag.status === "open");
73	  if (openReg) {
74	    fired.regulatory = `Open ${openReg.type} regulatory flag (${openReg.flagId}).`;
75	  }
76	
77	  const escalatedSupport = (world.supportCases || []).find(
78	    (c) => c.status === "open" && RULES.highSupportSeverities.includes(c.severity)
79	  );
80	  if (escalatedSupport) {
81	    fired.support = `Support case ${escalatedSupport.caseId} at ${escalatedSupport.severity} severity.`;
82	  }
83	
84	  const usage = world.usage || {};
85	  if (
86	    typeof usage.priorPeriodUnits === "number" &&
87	    typeof usage.currentPeriodUnits === "number" &&
88	    usage.priorPeriodUnits > 0 &&
89	    usage.currentPeriodUnits <= usage.priorPeriodUnits * (1 - RULES.usageDropFraction)
90	  ) {
91	    const dropPct = Math.round((1 - usage.currentPeriodUnits / usage.priorPeriodUnits) * 100);
92	    fired.usage = `Usage down ${dropPct}% period-over-period.`;
93	  }
94	
95	  return fired;
96	}
97	
98	// Ordered list of fired signals: [{ category, name, detail }] in SIGNAL_ORDER.
99	export function deriveSignals(world, now = NOW) {
100	  const fired = evaluateRisks(world, now);
101	  return SIGNAL_ORDER.filter((cat) => fired[cat]).map((cat) => ({
102	    category: cat,
103	    name: SIGNAL_NAME[cat],
104	    detail: fired[cat]
105	  }));
106	}
107	
108	// Owners derived from fired categories, deduped, in OWNER_ORDER.
109	export function deriveOwners(world, now = NOW) {
110	  const fired = evaluateRisks(world, now);
