import { withDb } from "./db.mjs";

export async function run(now = "2026-06-18T12:00:00.000Z") {
  await withDb(async (client) => {
    // Read raw facts
    const acctRow = (await client.query("SELECT * FROM accounts LIMIT 1")).rows[0];
    const reqRow = (await client.query("SELECT * FROM workflow_requests LIMIT 1")).rows[0];

    const account = {
      tier: acctRow.tier,
    };

    const invoices = JSON.parse(reqRow.invoices_json || "[]");
    const shipments = JSON.parse(reqRow.shipments_json || "[]");
    const regulatoryFlags = JSON.parse(reqRow.regulatory_json || "[]");
    const supportCases = JSON.parse(reqRow.support_json || "[]");
    const priorPeriodUnits = Number(reqRow.prior_period_units);
    const currentPeriodUnits = Number(reqRow.current_period_units);

    const nowDate = new Date(now);

    // Derive risk signals
    const signals = [];

    // Regulatory hold: a regulatory flag with status "open"
    const hasRegulatoryHold = regulatoryFlags.some((f) => f.status === "open");
    if (hasRegulatoryHold) signals.push("Regulatory hold");

    // Overdue invoice: unpaid invoice past due date AND amount >= $25,000
    const hasOverdueInvoice = invoices.some((inv) => {
      const unpaid = inv.status !== "paid";
      const pastDue = new Date(inv.due_date) < nowDate;
      const amount = Number(inv.amount_cents || 0) / 100;
      return unpaid && pastDue && amount >= 25000;
    });
    if (hasOverdueInvoice) signals.push("Overdue invoice");

    // Delayed shipment: no delivered date AND past SLA date
    const hasDelayedShipment = shipments.some((shp) => {
      const noDelivered = !shp.delivered_date;
      const pastSla = new Date(shp.sla_date) < nowDate;
      return noDelivered && pastSla;
    });
    if (hasDelayedShipment) signals.push("Delayed shipment");

    // Escalated support: open support case with severity high or critical
    const hasEscalatedSupport = supportCases.some(
      (sc) => sc.status === "open" && (sc.severity === "high" || sc.severity === "critical")
    );
    if (hasEscalatedSupport) signals.push("Escalated support");

    // Usage decline: current <= prior * 0.7
    const hasUsageDecline = currentPeriodUnits <= priorPeriodUnits * 0.7;
    if (hasUsageDecline) signals.push("Usage decline");

    // Qualification check
    const qualifyingTiers = ["strategic", "enterprise"];
    const qualifies = qualifyingTiers.includes(account.tier) && signals.length > 0;

    let status, nextStep, riskSummary, owners;

    if (!qualifies) {
      status = "Monitoring — no escalation required.";
      nextStep = "Continue standard monitoring.";
      riskSummary = "0 signals";
      owners = [];
    } else {
      status =
        "At-risk escalation active with executive recovery owner routing and customer-visible audit history.";
      riskSummary = `${signals.length} signals: ${signals.join(", ")}`;

      // Owner routing (dedupe, fixed order)
      const ownerSet = new Set();
      if (signals.includes("Regulatory hold")) ownerSet.add("Legal");
      if (signals.includes("Overdue invoice")) ownerSet.add("Finance");
      if (signals.includes("Delayed shipment")) ownerSet.add("Customer Success");
      if (signals.includes("Usage decline")) ownerSet.add("Customer Success");
      if (signals.includes("Escalated support")) ownerSet.add("Support");
      owners = [...ownerSet];

      // next_step: top owner recovery review by 16:00
      nextStep = `${owners[0]} recovery review by 16:00`;
    }

    // Clear existing persisted data
    await client.query("DELETE FROM workflow_state");
    await client.query("DELETE FROM owner_tasks");
    await client.query("DELETE FROM customer_messages");
    await client.query("DELETE FROM audit_events");

    // Persist workflow_state
    await client.query(
      "INSERT INTO workflow_state (status, next_step, risk_summary) VALUES ($1, $2, $3)",
      [status, nextStep, riskSummary]
    );

    // Persist owner_tasks
    const dueAt = new Date(nowDate.getTime() + 24 * 60 * 60 * 1000).toISOString();
    for (const owner of owners) {
      await client.query(
        "INSERT INTO owner_tasks (owner_group, title, due_at, status) VALUES ($1, $2, $3, $4)",
        [owner, `${owner} recovery action for strategic account`, dueAt, "open"]
      );
    }

    // Persist customer_messages
    if (qualifies) {
      const messageBody =
        `We are actively monitoring your account and have identified areas requiring immediate attention. ` +
        `Our team has been notified and is coordinating a response across the relevant departments. ` +
        `You can expect a follow-up from your dedicated account team within one business day. ` +
        `We appreciate your continued partnership and are committed to resolving these matters promptly.`;
      await client.query("INSERT INTO customer_messages (body) VALUES ($1)", [messageBody]);
    }

    // Persist audit_events
    await client.query(
      "INSERT INTO audit_events (event_type, description, customer_visible) VALUES ($1, $2, $3)",
      [
        "escalation_initiated",
        qualifies
          ? `Strategic account rescue workflow initiated. ${riskSummary}. Assigned to: ${owners.join(", ")}.`
          : "Account reviewed. No escalation required at this time.",
        true,
      ]
    );
  });
}

if (import.meta.url === `file://${process.argv[1]}`) {
